class Playground {
    async run(inputs) {
        const N = parseInt(inputs[0]) || 10;

        this.log(`Initializing Union Find with ${N} elements...`);
        this.uf.init(N);
        await this.await();

        // Helper to log state
        const logUnion = async (a, b) => {
            this.log(`Union(${a}, ${b})...`);
            const merged = this.uf.union(a, b);
            if (merged) this.log(`  -> Merged sets containing ${a} and ${b}`);
            else this.log(`  -> ${a} and ${b} already in same set`);
            await this.await();
        };

        // Demo Sequence
        this.log('Step 1: Create some pairs');
        await logUnion(0, 1);
        await logUnion(2, 3);
        await logUnion(4, 5);
        await logUnion(6, 7);

        this.log('Step 2: Connect the pairs');
        await logUnion(1, 3); // Connects (0-1) and (2-3) -> (0-1-2-3)
        await logUnion(5, 7); // Connects (4-5) and (6-7) -> (4-5-6-7)

        this.log('Step 3: Connect big components');
        await logUnion(0, 6); // Connects the two big sets

        this.log('Step 4: Path Compression Demo');
        this.log('Finding 7 (should point to root 0 or near it after compression)');
        const root = this.uf.find(7);
        this.log(`Root of 7 is ${root}`);
        await this.await();

        this.log('Done.');
    }
}
